<?php require "vendor/autoload.php"; $app = require_once "bootstrap/app.php"; $kernel = $app->make(Illuminate\Contracts\Console\Kernel::class); $kernel->bootstrap(); $plan = App\Models\Plan::first(); $zona = App\Models\Zona::first(); $voucher = App\Models\Voucher::create(["zona_id" => $zona->id, "plan_id" => $plan->id, "codigo" => "TEST" . time(), "estado" => "pendiente", "comprador_email" => null]); try { $url = (new App\Services\StripeService())->crearSesionCheckout($plan, $zona, $voucher); echo "URL: " . $url . "\n"; } catch (\Exception $e) { echo "ERROR: " . $e->getMessage() . "\n"; }
